import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import { Platform } from '@prisma/client';
import { KalshiService } from '@/lib/services/kalshi.service';
import { PolymarketService } from '@/lib/services/polymarket.service';
import { MatcherService } from '@/lib/services/matcher.service';
import { SemanticMatcherService } from '@/lib/services/semantic-matcher.service';

export const dynamic = 'force-dynamic';
export const maxDuration = 300;

const MIN_KEYWORD_SCORE = 0.6;
const MAX_PAIRS_TO_EVALUATE = 20;
const RATE_LIMIT_DELAY = 1100;

export async function GET(req: NextRequest) {
  const authHeader = req.headers.get('authorization');
  const cronSecret = process.env.CRON_SECRET;

  if (cronSecret && authHeader !== `Bearer ${cronSecret}`) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const startedAt = Date.now();
  const MAX_DURATION = 240_000;

  let newKalshiMarkets = 0;
  let newPolyMarkets = 0;
  let pairsEvaluated = 0;
  let newMatches = 0;
  let errors = 0;

  try {
    const kalshiService = new KalshiService();
    const polyService = new PolymarketService();
    const matcherService = new MatcherService();
    const semanticMatcher = new SemanticMatcherService();

    // PASO 1: Detectar markets nuevos de Kalshi
    // Fetcha una página de markets recientes y compara contra DB
    console.log('[Discovery] Checking for new Kalshi markets...');

    const newKalshiIds: string[] = [];

    try {
      const kalshiResponse = await kalshiService.getMarkets({
        status: 'open',
        limit: 200
      });

      const markets = (kalshiResponse.markets || []).filter(
        (m) =>
          !m.ticker.startsWith('KXMVE') && !m.ticker.includes('CROSSCATEGORY')
      );

      if (markets.length > 0) {
        const tickers = markets.map((m) => m.ticker);
        const existing = await prisma.market.findMany({
          where: { platform: Platform.KALSHI, externalId: { in: tickers } },
          select: { externalId: true }
        });
        const existingSet = new Set(existing.map((m) => m.externalId));
        const newMarkets = markets.filter((m) => !existingSet.has(m.ticker));

        for (const market of newMarkets) {
          try {
            const normalized = kalshiService.normalizeMarket(market);
            await prisma.market.create({ data: normalized });
            newKalshiIds.push(market.ticker);
            newKalshiMarkets++;
          } catch {
            errors++;
          }
        }
      }
    } catch (e) {
      console.error('[Discovery] Kalshi fetch error:', e);
      errors++;
    }

    console.log(`[Discovery] ${newKalshiMarkets} new Kalshi markets`);

    // PASO 2: Detectar markets nuevos de Polymarket
    // Fetcha los eventos más recientes y compara contra DB
    console.log('[Discovery] Checking for new Polymarket markets...');

    const newPolyIds: string[] = [];

    try {
      const response = await fetch(
        'https://gamma-api.polymarket.com/events?active=true&closed=false&limit=100&offset=0',
        { headers: { Accept: 'application/json' } }
      );

      if (response.ok) {
        const events = await response.json();

        const allMarkets: Array<{
          market: Record<string, unknown>;
          event: { id: string; slug?: string; title?: string };
        }> = [];

        for (const event of events || []) {
          const markets = event.markets?.length > 0 ? event.markets : [event];
          for (const market of markets) {
            const externalId = String(market.id ?? market.conditionId ?? '');
            if (externalId) {
              allMarkets.push({
                market: { ...market },
                event: { id: event.id, slug: event.slug, title: event.title }
              });
            }
          }
        }

        if (allMarkets.length > 0) {
          const externalIds = allMarkets.map((m) =>
            String(m.market.id ?? m.market.conditionId ?? '')
          );
          const existing = await prisma.market.findMany({
            where: {
              platform: Platform.POLYMARKET,
              externalId: { in: externalIds }
            },
            select: { externalId: true }
          });
          const existingSet = new Set(existing.map((m) => m.externalId));

          for (const { market, event } of allMarkets) {
            const externalId = String(market.id ?? market.conditionId ?? '');
            if (!externalId || existingSet.has(externalId)) continue;

            try {
              const normalized = polyService.normalizeMarket(market, event);
              await prisma.market.create({ data: normalized });
              newPolyIds.push(externalId);
              newPolyMarkets++;
            } catch {
              errors++;
            }
          }
        }
      }
    } catch (e) {
      console.error('[Discovery] Polymarket fetch error:', e);
      errors++;
    }

    console.log(`[Discovery] ${newPolyMarkets} new Polymarket markets`);

    // Actualizar SyncLogs
    if (newKalshiMarkets > 0) {
      await prisma.syncLog.create({
        data: {
          platform: Platform.KALSHI,
          lastSyncedAt: new Date(),
          marketsCount: newKalshiMarkets,
          duration: Math.round((Date.now() - startedAt) / 1000),
          errors
        }
      });
    }

    if (newPolyMarkets > 0) {
      await prisma.syncLog.create({
        data: {
          platform: Platform.POLYMARKET,
          lastSyncedAt: new Date(),
          marketsCount: newPolyMarkets,
          duration: Math.round((Date.now() - startedAt) / 1000),
          errors
        }
      });
    }

    // PASO 3: Matching de markets nuevos
    if (
      (newKalshiMarkets > 0 || newPolyMarkets > 0) &&
      Date.now() - startedAt < MAX_DURATION
    ) {
      console.log('[Discovery] Running matcher on new markets...');

      // Obtener los markets recién insertados
      const newKalshi =
        newKalshiIds.length > 0
          ? await prisma.market.findMany({
              where: {
                platform: Platform.KALSHI,
                externalId: { in: newKalshiIds }
              }
            })
          : [];

      const newPoly =
        newPolyIds.length > 0
          ? await prisma.market.findMany({
              where: {
                platform: Platform.POLYMARKET,
                externalId: { in: newPolyIds }
              }
            })
          : [];

      // Pool de candidatos
      const polyPool = await prisma.market.findMany({
        where: { platform: Platform.POLYMARKET, active: true },
        orderBy: { volume24h: 'desc' },
        take: 2000
      });

      const kalshiPool = await prisma.market.findMany({
        where: { platform: Platform.KALSHI, active: true },
        orderBy: { volume24h: 'desc' },
        take: 2000
      });

      // Nuevos Kalshi contra pool Polymarket
      for (const kalshiMarket of newKalshi) {
        if (Date.now() - startedAt > MAX_DURATION) break;
        if (pairsEvaluated >= MAX_PAIRS_TO_EVALUATE) break;

        const candidates = matcherService.findMatchesFromCandidates(
          kalshiMarket,
          polyPool,
          MIN_KEYWORD_SCORE
        );

        for (const candidate of candidates.slice(0, 3)) {
          if (Date.now() - startedAt > MAX_DURATION) break;
          if (pairsEvaluated >= MAX_PAIRS_TO_EVALUATE) break;

          const polyMarket = candidate.market;

          const existing = await prisma.marketMatch.findFirst({
            where: {
              OR: [
                { marketAId: kalshiMarket.id, marketBId: polyMarket.id },
                { marketAId: polyMarket.id, marketBId: kalshiMarket.id }
              ]
            }
          });
          if (existing) continue;

          try {
            pairsEvaluated++;
            const result = await semanticMatcher.evaluatePair(
              kalshiMarket,
              polyMarket
            );
            if (result.isEquivalent) {
              newMatches++;
              console.log(
                `[Discovery] MATCH: ${kalshiMarket.question.slice(0, 60)} ↔ ${polyMarket.question.slice(0, 60)}`
              );
            }
            await new Promise((r) => setTimeout(r, RATE_LIMIT_DELAY));
          } catch {
            errors++;
          }
        }
      }

      // Nuevos Polymarket contra pool Kalshi
      for (const polyMarket of newPoly) {
        if (Date.now() - startedAt > MAX_DURATION) break;
        if (pairsEvaluated >= MAX_PAIRS_TO_EVALUATE) break;

        const candidates = matcherService.findMatchesFromCandidates(
          polyMarket,
          kalshiPool,
          MIN_KEYWORD_SCORE
        );

        for (const candidate of candidates.slice(0, 3)) {
          if (Date.now() - startedAt > MAX_DURATION) break;
          if (pairsEvaluated >= MAX_PAIRS_TO_EVALUATE) break;

          const kalshiMarket = candidate.market;

          const existing = await prisma.marketMatch.findFirst({
            where: {
              OR: [
                { marketAId: polyMarket.id, marketBId: kalshiMarket.id },
                { marketAId: kalshiMarket.id, marketBId: polyMarket.id }
              ]
            }
          });
          if (existing) continue;

          try {
            pairsEvaluated++;
            const result = await semanticMatcher.evaluatePair(
              polyMarket,
              kalshiMarket
            );
            if (result.isEquivalent) {
              newMatches++;
              console.log(
                `[Discovery] MATCH: ${polyMarket.question.slice(0, 60)} ↔ ${kalshiMarket.question.slice(0, 60)}`
              );
            }
            await new Promise((r) => setTimeout(r, RATE_LIMIT_DELAY));
          } catch {
            errors++;
          }
        }
      }
    } else {
      console.log('[Discovery] No new markets, skipping matching');
    }

    const duration = Date.now() - startedAt;
    console.log(
      `[Discovery] Done: ${newKalshiMarkets} new Kalshi, ${newPolyMarkets} new Poly, ${pairsEvaluated} pairs evaluated, ${newMatches} new matches in ${duration}ms`
    );

    return NextResponse.json({
      success: true,
      newKalshiMarkets,
      newPolyMarkets,
      pairsEvaluated,
      newMatches,
      errors,
      durationMs: duration,
      runAt: new Date().toISOString()
    });
  } catch (err) {
    console.error('[Discovery] Fatal error:', err);
    return NextResponse.json(
      { error: err instanceof Error ? err.message : 'Unknown error' },
      { status: 500 }
    );
  }
}
